<template>
    <div class="grey darken-4 full bg" v-bind:style="{'background-image' : 'url('+ $store.state.base_url + '/uploads/subscriptions/' + details.id + '/' + details.background +')'}">
        <img  height="60" alt="" class="fixed-image-top" :src="$store.state.base_url + '/uploads/subscriptions/' + details.id + '/' + details.logo">
        <v-speed-dial v-model="dialShare" 
            fixed right bottom direction="left" open-on-hover>
            <template v-slot:activator>
            <v-btn fab bottom large color="primary">
                <v-icon v-if="dialShare">mdi-close</v-icon>
                <v-icon v-else>mdi-share-variant</v-icon>
            </v-btn>
            </template>
            <v-btn dark fab bottom color="blue" large :href="`https://www.facebook.com/sharer/sharer.php?u=${shareUrl}`" target="_blank">
                <v-icon>mdi-facebook</v-icon>
            </v-btn>
            <v-btn dark fab bottom color="green" large :href="`https://wa.me/?text=Checkout%20this%20page.%20${shareUrl}`" target="_blank">
                <v-icon>mdi-whatsapp</v-icon>
            </v-btn>
        </v-speed-dial>
        <div class="pa-10">
            <masonry-wall :items="posts" :ssr-columns="1" :column-width="300" :gap="16">
                <template #default="{ item, index }">
                    <v-card
                        class="mx-auto"
                        :style="{'background-color' : item.background}"
                        max-width="800"
                        :to="{name : 'Details', params : {id: item.id, uid : item.uid}}"
                        shaped
                    >
                        <v-img
                            v-if="item.image"
                            :src="$store.state.base_url + '/uploads/posts/images/' + item.id + '/' + item.image"
                            max-height="500"
                            position="center"
                        ></v-img>
                        <v-card-text class="text-center pre-wrap" :style="{'color' : item.font_color}">
                            {{ item.message }}
                        </v-card-text>

                        <v-card-actions>
                            <v-list-item dense>
                                <v-list-item-avatar color="grey darken-4">
                                    <span class="text-h5 white--text">{{ item.name.substring(0, 1) }}</span>
                                </v-list-item-avatar>
                                <v-list-item-content>
                                    <v-list-item-subtitle :style="{'color' : item.font_color}">{{ item.name }}</v-list-item-subtitle>
                                    <v-list-item-subtitle v-if="details.show_timestamp == 1" :style="{'color' : item.font_color}">{{ item.created_at }}</v-list-item-subtitle>
                                </v-list-item-content>
                            </v-list-item>
                        </v-card-actions>
                    </v-card>
                </template>
            </masonry-wall>
        </div>
    </div>
    
</template>
<style scoped>
    .back-border {
        opacity: .6;
        width: 100%;
        height: 15px;
        background: #000;
        position:fixed;
        top: 0px;
        z-index:9;
    }
    .fixed-image-top {
        position: fixed;
        z-index: 10;
        right : 15px;
        top: 15px;
    }
    .full {
        width: 100%;
        height : 100%;
    }
    .bg {
        background-size:cover;
        background-repeat: no-repeat;
        background-color: #fff;
        background-position: top;
        background-attachment: fixed;
    }
    .pre-wrap {
        white-space: pre-wrap; 
    }
</style>
<script>
import axios from 'axios'
import Pusher from '@/plugins/pusher.js'
export default {
    name : 'SlideShowView',
    data () {
        return {
            posts: [],
            timer : null,
            details : {},
            metaTags : {},
            shareUrl : null,
            interval : 180000,
            dialShare : null
        }
    },
    mounted() {
        Pusher.logToConsole = false;

        var pusher = new Pusher('f69685e43c93fed4d15c', {
            cluster: 'ap1'
        });

        var channel = pusher.subscribe('my-channel');
        channel.bind('my-event', data => {
            if(data.code == this.details.event_code) {
                console.log(data);
                if(data.type == 'approve') {
                    var posts = this.posts;
                    posts.unshift(data);
                    this.posts = JSON.parse(JSON.stringify(posts));

                    clearInterval(this.timer);

                    this.timer = setInterval(()=>{
                        this.refresh(1);
                        console.log('refreshed');
                    }, this.interval);
                }
                else if(data.type == 'remove') {
                    this.refresh(0);
                }
            }
        });

        this.getEventDetails();
    },
    destroyed() {
        clearInterval(this.timer)
    },
    methods : {
        getEventDetails() {
            axios({
                url : this.$store.state.api_url + '/event-details/' + this.$route.params.code,
                method : 'GET',
            }).then(res => {
                this.details = res.data;
                this.shareUrl = 'https://livesocialfeed.com/events/' + this.details.key
                this.interval = (this.details.rotation_interval * 60) * 1000;

                this.timer = setInterval(()=>{
                    this.refresh(1);
                    console.log('refreshed');
                }, this.interval);
                this.refresh();
            });
        },
        refresh(randomized = 0) {
            axios({
                url : this.$store.state.api_url + '/posts/' + this.$route.params.code,
                method : 'GET',
                params : {randomized : randomized, approved : 1}
            }).then(res => {
                this.posts = res.data;
            });
        }
    }
}
</script>